import{_ as o,o as t,c as a,ag as r}from"./chunks/framework.BDReElpY.js";const g=JSON.parse('{"title":"Glossary","description":"","frontmatter":{},"headers":[],"relativePath":"guide/glossary.md","filePath":"guide/glossary.md"}'),n={name:"guide/glossary.md"};function s(i,e,c,d,l,p){return t(),a("div",null,[...e[0]||(e[0]=[r('<h1 id="glossary" tabindex="-1">Glossary <a class="header-anchor" href="#glossary" aria-label="Permalink to &quot;Glossary&quot;">​</a></h1><p>Key terms and concepts in the Vex ecosystem.</p><h2 id="a" tabindex="-1">A <a class="header-anchor" href="#a" aria-label="Permalink to &quot;A&quot;">​</a></h2><p><strong>AOT (Ahead-of-Time)</strong> -- Compilation mode that produces a standalone native binary before execution. Vex is AOT-only.</p><p><strong>Async Function</strong> -- Function declared with <code>async fn</code> that can suspend at <code>await</code> points. Compiled to a state machine coroutine.</p><p><strong>Autograd</strong> -- Automatic differentiation system for computing gradients of tensor operations, used in machine learning.</p><h2 id="b" tabindex="-1">B <a class="header-anchor" href="#b" aria-label="Permalink to &quot;B&quot;">​</a></h2><p><strong>Borrowing</strong> -- Creating a reference (<code>&amp;T</code> or <code>&amp;T!</code>) to a value without taking ownership. Governed by the borrow checker&#39;s NLL (Non-Lexical Lifetime) analysis.</p><p><strong>Box&lt;T&gt;</strong> -- Heap-allocated smart pointer. The VUMM system infers whether it becomes Unique (single-owner), SharedRc (reference-counted, single-thread), or AtomicArc (atomic reference-counted, multi-thread).</p><p><strong>Builtin</strong> -- A compiler intrinsic function or type available without imports. Prefixed with <code>#</code> (e.g., <code>#sizeof&lt;T&gt;()</code>).</p><h2 id="c" tabindex="-1">C <a class="header-anchor" href="#c" aria-label="Permalink to &quot;C&quot;">​</a></h2><p><strong>Channel&lt;T&gt;</strong> -- Multi-producer, multi-consumer bounded channel for communication between concurrent tasks. Use <code>ch &lt;- val</code> to send and <code>&lt;-ch</code> to receive.</p><p><strong>Closure</strong> -- Anonymous function that can capture variables from its enclosing scope. Syntax: <code>|params| expression</code>.</p><p><strong>Comptime</strong> -- Compile-time code execution. Functions and expressions evaluated at build time rather than runtime.</p><p><strong>Contract</strong> -- A trait-like interface defining shared behavior. Types implement contracts to gain capabilities. Syntax: <code>contract Name { method(); }</code>.</p><p><strong>Copy Type</strong> -- A type that can be duplicated by bitwise copy. All primitives are Copy. Non-Copy types are moved on assignment.</p><h2 id="d" tabindex="-1">D <a class="header-anchor" href="#d" aria-label="Permalink to &quot;D&quot;">​</a></h2><p><strong>Defer</strong> -- Statement that schedules code to run when the current scope exits (Go-style RAII). Syntax: <code>defer file.close()</code>.</p><p><strong>Drop</strong> -- The RAII cleanup mechanism. When a value implementing <code>Drop</code> goes out of scope, its <code>drop()</code> method is called automatically.</p><p><strong>DynMask</strong> -- Runtime-sized boolean mask for SIMD operations. Fat pointer: <code>{ ptr: *i8, len: i64 }</code>.</p><p><strong>DynTensor&lt;T&gt;</strong> -- Runtime-sized tensor. Fat pointer: <code>{ ptr: *T, len: i64 }</code>. Used when tensor dimensions are not known at compile time.</p><h2 id="e" tabindex="-1">E <a class="header-anchor" href="#e" aria-label="Permalink to &quot;E&quot;">​</a></h2><p><strong>Enum</strong> -- Sum type (tagged union) that can hold one of several variants. Each variant can carry payload data. Syntax: <code>enum Option&lt;T&gt; { Some(T), None }</code>.</p><p><strong>Expression-Oriented</strong> -- Most language constructs (if, match, loop, blocks) are expressions that return values, not just statements.</p><h2 id="f" tabindex="-1">F <a class="header-anchor" href="#f" aria-label="Permalink to &quot;F&quot;">​</a></h2><p><strong>FFI (Foreign Function Interface)</strong> -- Mechanism for calling C functions from Vex and vice versa. Uses <code>extern &quot;C&quot;</code> blocks.</p><p><strong>Freestanding</strong> -- Mode where the standard library is not available (<code>#![no_std]</code>). Used for embedded/bare-metal programming.</p><p><strong>Fusion (SIR Fusion)</strong> -- Optimization that merges multiple tensor operations into a single kernel launch, reducing GPU overhead.</p><h2 id="g" tabindex="-1">G <a class="header-anchor" href="#g" aria-label="Permalink to &quot;G&quot;">​</a></h2><p><strong>go Block</strong> -- Launches a fire-and-forget concurrent task on the M:N scheduler. Syntax: <code>go { await task(); }</code>.</p><p><strong>graph fn</strong> -- GPU kernel function compiled through the SIR pipeline to target Metal, CUDA, SPIR-V, WGSL, etc.</p><h2 id="h" tabindex="-1">H <a class="header-anchor" href="#h" aria-label="Permalink to &quot;H&quot;">​</a></h2><p><strong>HIR (High-Level IR)</strong> -- The intermediate representation after parsing and type checking, before lowering to SIR or LLVM IR.</p><p><strong>Horizontal Reduction</strong> -- Collapsing a tensor/array to a scalar using an associative operation. Syntax: <code>&lt;+ arr</code> (sum), <code>&lt;* arr</code> (product), <code>&lt;?| arr</code> (min), <code>&gt;?| arr</code> (max).</p><h2 id="i" tabindex="-1">I <a class="header-anchor" href="#i" aria-label="Permalink to &quot;I&quot;">​</a></h2><p><strong>Iterator</strong> -- Contract for types that yield a sequence of values. Powers <code>for</code> loops. Method: <code>next(): Option&lt;Self.Item&gt;</code>.</p><h2 id="j" tabindex="-1">J <a class="header-anchor" href="#j" aria-label="Permalink to &quot;J&quot;">​</a></h2><p><strong>LLVM</strong> -- The compiler backend that Vex uses for native code generation (version 21.1.8). Vex compiles to LLVM IR which is then lowered to machine code for the target architecture.</p><h2 id="l" tabindex="-1">L <a class="header-anchor" href="#l" aria-label="Permalink to &quot;L&quot;">​</a></h2><p><strong>Lifetime</strong> -- The span of execution during which a reference is valid. Vex uses NLL (Non-Lexical Lifetime) analysis to verify borrow safety.</p><p><strong>LTO (Link-Time Optimization)</strong> -- Cross-module optimization that preserves LLVM bitcode through the link step. ThinLTO (fast, good results) and FullLTO (slow, best results).</p><h2 id="m" tabindex="-1">M <a class="header-anchor" href="#m" aria-label="Permalink to &quot;M&quot;">​</a></h2><p><strong>M:N Scheduler</strong> -- User-space scheduler that multiplexes M coroutines onto N OS threads. Uses work-stealing for load balancing.</p><p><strong>Mask&lt;N&gt;</strong> -- Compile-time-sized SIMD boolean vector resulting from tensor comparisons. Supports bitwise operations and reduction queries.</p><p><strong>Move Semantics</strong> -- For non-Copy types, assignment transfers ownership. The source becomes inaccessible after a move.</p><h2 id="n" tabindex="-1">N <a class="header-anchor" href="#n" aria-label="Permalink to &quot;N&quot;">​</a></h2><p><strong>never</strong> -- The bottom type with no possible values. Return type of diverging functions (<code>$panic</code>, <code>$abort</code>, infinite <code>loop</code>). Coerces to any type.</p><p><strong>NLL (Non-Lexical Lifetimes)</strong> -- The borrow checker algorithm that computes liveness based on actual usage rather than lexical scope boundaries.</p><h2 id="o" tabindex="-1">O <a class="header-anchor" href="#o" aria-label="Permalink to &quot;O&quot;">​</a></h2><p><strong>Operator Overloading</strong> -- Defining custom behavior for operators (<code>+</code>, <code>==</code>, <code>[]</code>, etc.) by implementing the corresponding contract (<code>Add</code>, <code>Eq</code>, <code>Index</code>).</p><p><strong>Option&lt;T&gt;</strong> -- Type representing a value that may be absent. Variants: <code>Some(T)</code> or <code>None</code>. Safe alternative to null pointers.</p><p><strong>OrderedMap&lt;K, V&gt;</strong> -- Hash map that preserves insertion order. Combines O(1) lookup with predictable iteration.</p><p><strong>Ownership</strong> -- Each value in Vex has exactly one owner at a time. When the owner goes out of scope, the value is dropped.</p><h2 id="p" tabindex="-1">P <a class="header-anchor" href="#p" aria-label="Permalink to &quot;P&quot;">​</a></h2><p><strong>Pin&lt;T&gt;</strong> -- Wrapper that prevents a value from being moved in memory. Required for self-referential types where fields contain pointers to other fields of the same value.</p><p><strong>Prelude</strong> -- Set of types and functions always available without explicit import. Includes <code>Option</code>, <code>Result</code>, <code>Vec</code>, <code>Box</code>, <code>Ptr</code>, <code>Span</code>, <code>string</code>, etc.</p><p><strong>Ptr&lt;T&gt;</strong> -- Safe typed pointer wrapper providing methods like <code>read()</code>, <code>write()</code>, <code>readAt(index)</code>, <code>offset(n)</code> without manual pointer arithmetic.</p><p><strong>ptr</strong> -- Untyped opaque raw pointer (equivalent to C&#39;s <code>void*</code>).</p><h2 id="r" tabindex="-1">R <a class="header-anchor" href="#r" aria-label="Permalink to &quot;R&quot;">​</a></h2><p><strong>Range</strong> -- Iterator type for numeric sequences. Syntax: <code>0..10</code> (exclusive), <code>0..=10</code> (inclusive), <code>..</code> (full range).</p><p><strong>RawBuf</strong> -- Zero-cost byte-level memory accessor for low-level/stdlib code. Wraps a <code>ptr</code> with typed <code>load&lt;T&gt;(offset)</code> and <code>store&lt;T&gt;(offset, value)</code>.</p><p><strong>Result&lt;T, E&gt;</strong> -- Type representing either success (<code>Ok(T)</code>) or failure (<code>Err(E)</code>). Primary error handling mechanism with <code>?</code> operator for propagation and <code>!&gt;</code> rescue operator for fallback values.</p><p><strong>Rescue Operator (<code>!&gt;</code>)</strong> -- Postfix operator that extracts a value from <code>Option&lt;T&gt;</code> or <code>Result&lt;T,E&gt;</code>, providing a fallback on <code>None</code>/<code>Err</code>. Syntax: <code>val !&gt; fallback</code> or <code>val !&gt; || { computeFallback() }</code>. The idiomatic Vex alternative to <code>.unwrap()</code> (which does not exist in Vex).</p><h2 id="s" tabindex="-1">S <a class="header-anchor" href="#s" aria-label="Permalink to &quot;S&quot;">​</a></h2><p><strong>SIMD (Single Instruction, Multiple Data)</strong> -- CPU instruction set extension for parallel data processing. Vex auto-vectorizes array math to SIMD instructions.</p><p><strong>SIR (Silicon IR)</strong> -- Vex&#39;s intermediate representation for GPU and accelerator computation. Write once, target Metal/CUDA/SPIR-V/WGSL/CPU SIMD.</p><p><strong>Span&lt;T&gt;</strong> -- Bounds-checked fat pointer (non-owning view): <code>{ data: *T, length: usize }</code>. Safe slice-like access without ownership.</p><p><strong>str (VexStr)</strong> -- Borrowed string view (16 bytes, Copy): <code>{ data: ptr, length: usize }</code>. Used for string literals and borrowing string data.</p><p><strong>string (VexString)</strong> -- Owned heap-allocated string (16 bytes). Supports inline storage for short strings (SSO). Omni-string compatible with UTF-8, UTF-16, Latin-1.</p><p><strong>Struct</strong> -- Composite data type with named fields. Can implement contracts, have methods, and define constructors.</p><h2 id="t" tabindex="-1">T <a class="header-anchor" href="#t" aria-label="Permalink to &quot;T&quot;">​</a></h2><p><strong>Tensor&lt;T, N&gt;</strong> -- Static-sized SIMD vector. Arrays auto-promote to tensors when performing arithmetic. Small tensors (&lt;= 64B) live in SIMD registers.</p><p><strong>Threadgroup Memory</strong> -- GPU on-chip shared memory within a workgroup (thread block). Declared with <code>threadgroup</code> keyword in <code>graph fn</code>. Much faster than global GPU memory.</p><h2 id="u" tabindex="-1">U <a class="header-anchor" href="#u" aria-label="Permalink to &quot;U&quot;">​</a></h2><p><strong>Unit Type (<code>()</code>)</strong> -- Zero-size type with exactly one value: <code>()</code>. Default return type for functions without a meaningful return value. Not the same as C&#39;s <code>void</code>.</p><p><strong>unsafe</strong> -- Keyword marking a block where the compiler relaxes certain safety guarantees. Required for raw pointer dereference, FFI calls, and mutable static access.</p><h2 id="v" tabindex="-1">V <a class="header-anchor" href="#v" aria-label="Permalink to &quot;V&quot;">​</a></h2><p><strong>Vec&lt;T&gt;</strong> -- Dynamic array with automatic growth. Fields: <code>{ data: *T!, length: usize, capacity: usize }</code>. Primary collection type.</p><p><strong>VUMM (Vex Unified Memory Model)</strong> -- Automatic ownership strategy inference for <code>Box&lt;T&gt;</code>. The compiler chooses Unique (single owner), SharedRc (reference counted, single thread), or AtomicArc (atomic reference count, multi-thread) based on usage analysis.</p><h2 id="w" tabindex="-1">W <a class="header-anchor" href="#w" aria-label="Permalink to &quot;W&quot;">​</a></h2><p><strong>Work-Stealing</strong> -- Scheduling algorithm where idle worker threads &quot;steal&quot; tasks from busy workers&#39; queues. Provides automatic load balancing for the M:N scheduler.</p>',81)])])}const u=o(n,[["render",s]]);export{g as __pageData,u as default};
